import hashlib
import os

def _derive_key(passphrase, length=32):
    """Derive fixed-length key from passphrase via SHA-256."""
    if isinstance(passphrase, str):
        passphrase = passphrase.encode('utf-8')
    return hashlib.sha256(passphrase).digest()[:length]

def xor_encrypt(data, key):
    """XOR stream cipher with multi-byte key cycling."""
    if isinstance(data, str):
        data = data.encode('utf-8')
    if isinstance(key, str):
        key = _derive_key(key)
    elif isinstance(key, bytes) and len(key) < 16:
        key = _derive_key(key)
    key_len = len(key)
    return bytes(b ^ key[i % key_len] for i, b in enumerate(data))

def xor_decrypt(data, key):
    """XOR decryption (symmetric with encryption)."""
    return xor_encrypt(data, key)

def xor_encrypt_with_iv(data, passphrase):
    """XOR encryption with random IV prepended for non-deterministic output."""
    if isinstance(data, str):
        data = data.encode('utf-8')
    iv = os.urandom(16)
    derived = _derive_key(passphrase)
    full_key = hashlib.sha256(derived + iv).digest()
    encrypted = xor_encrypt(data, full_key)
    return iv + encrypted

def xor_decrypt_with_iv(encrypted, passphrase):
    """Decrypt data encrypted with xor_encrypt_with_iv."""
    iv = encrypted[:16]
    ciphertext = encrypted[16:]
    derived = _derive_key(passphrase)
    full_key = hashlib.sha256(derived + iv).digest()
    return xor_encrypt(ciphertext, full_key)

