import hashlib
import os
import struct

def _pad(data, bs=16):
    n = bs - (len(data) % bs)
    return data + bytes([n] * n)

def _unpad(data):
    n = data[-1]
    if n < 1 or n > 16 or data[-n:] != bytes([n] * n):
        raise ValueError('Invalid padding')
    return data[:-n]

def _key_schedule(key):
    """Generate 16 round keys from master key via SHA-256 chaining."""
    rounds, current = [], key
    for i in range(16):
        current = hashlib.sha256(current + struct.pack('>I', i)).digest()
        rounds.append(current[:16])
    return rounds

def _block_encrypt(block, round_keys):
    """Encrypt a single 16-byte block through XOR rounds with byte permutation."""
    state = bytearray(block)
    for rk in round_keys:
        state = bytearray(s ^ k for s, k in zip(state, rk))
        state = bytearray(state[((i * 5) + 3) % 16] for i in range(16))
    return bytes(state)

def _block_decrypt(block, round_keys):
    """Decrypt a single 16-byte block (reverse round operations)."""
    inv_perm = [0] * 16
    for i in range(16):
        inv_perm[((i * 5) + 3) % 16] = i
    state = bytearray(block)
    for rk in reversed(round_keys):
        state = bytearray(state[inv_perm[i]] for i in range(16))
        state = bytearray(s ^ k for s, k in zip(state, rk))
    return bytes(state)

def encrypt_payload(data, key):
    """Encrypt data: returns IV (16 bytes) + ciphertext. CBC mode."""
    if isinstance(data, str): data = data.encode('utf-8')
    if isinstance(key, str): key = key.encode('utf-8')
    derived = hashlib.sha256(key).digest()
    round_keys = _key_schedule(derived)
    iv = os.urandom(16)
    padded = _pad(data)
    ciphertext, prev = b'', iv
    for i in range(0, len(padded), 16):
        block = bytes(p ^ c for p, c in zip(padded[i:i+16], prev))
        enc = _block_encrypt(block, round_keys)
        ciphertext += enc
        prev = enc
    return iv + ciphertext

def decrypt_payload(encrypted, key):
    """Decrypt IV+ciphertext produced by encrypt_payload."""
    if isinstance(key, str): key = key.encode('utf-8')
    derived = hashlib.sha256(key).digest()
    round_keys = _key_schedule(derived)
    iv, ciphertext = encrypted[:16], encrypted[16:]
    plaintext, prev = b'', iv
    for i in range(0, len(ciphertext), 16):
        block = ciphertext[i:i+16]
        dec = _block_decrypt(block, round_keys)
        plaintext += bytes(d ^ p for d, p in zip(dec, prev))
        prev = block
    return _unpad(plaintext)

