import os
import subprocess
import sys

def _parse_proc_linux():
    """Enumerate processes from /proc on Linux."""
    procs = []
    for pid_dir in os.listdir('/proc'):
        if not pid_dir.isdigit(): continue
        pid = int(pid_dir)
        entry = {'pid': pid, 'name': '', 'user': '', 'cmdline': ''}
        try:
            with open('/proc/{}/comm'.format(pid)) as f: entry['name'] = f.read().strip()
        except (PermissionError, FileNotFoundError, ProcessLookupError): pass
        try:
            with open('/proc/{}/cmdline'.format(pid)) as f: entry['cmdline'] = f.read().replace('\x00', ' ').strip()
        except (PermissionError, FileNotFoundError, ProcessLookupError): pass
        try:
            with open('/proc/{}/status'.format(pid)) as f:
                for line in f:
                    if line.startswith('Uid:'):
                        uid = int(line.split()[1])
                        try:
                            import pwd; entry['user'] = pwd.getpwuid(uid).pw_name
                        except (ImportError, KeyError): entry['user'] = str(uid)
                        break
        except (PermissionError, FileNotFoundError, ProcessLookupError): pass
        procs.append(entry)
    return procs

def _parse_ps_macos():
    """Enumerate processes via ps on macOS."""
    procs = []
    try:
        out = subprocess.check_output(['ps', 'aux'], text=True, timeout=10)
        for line in out.strip().split('\n')[1:]:
            parts = line.split(None, 10)
            if len(parts) >= 11:
                procs.append({'pid': int(parts[1]), 'name': os.path.basename(parts[10].split()[0]),
                              'user': parts[0], 'cmdline': parts[10]})
    except Exception: pass
    return procs

def _parse_tasklist_windows():
    """Enumerate processes via tasklist on Windows."""
    procs = []
    try:
        out = subprocess.check_output(['tasklist', '/v', '/fo', 'csv'],
                                       text=True, timeout=15, stderr=subprocess.DEVNULL)
        import csv, io
        reader = csv.reader(io.StringIO(out))
        next(reader, None)
        for row in reader:
            if len(row) >= 2:
                procs.append({'pid': int(row[1].strip('" ')), 'name': row[0].strip('" '),
                              'user': row[6].strip('" ') if len(row) > 6 else '', 'cmdline': row[0].strip('" ')})
    except Exception: pass
    return procs

def list_processes():
    """Cross-platform process enumeration. Returns list of dicts: {pid, name, user, cmdline}."""
    if sys.platform.startswith('linux'): return _parse_proc_linux()
    elif sys.platform == 'darwin': return _parse_ps_macos()
    elif sys.platform == 'win32' or os.name == 'nt': return _parse_tasklist_windows()
    return []

