import os
import sys
import subprocess
import ctypes

def check_privileges():
    """Check current privilege level and system context.
    Returns dict with is_admin, username, groups, hostname, os_type."""
    info = {
        'is_admin': False,
        'username': '',
        'groups': [],
        'hostname': '',
        'os_type': sys.platform,
        'pid': os.getpid(),
        'uid': None,
        'integrity_level': ''
    }
    info['hostname'] = os.environ.get('COMPUTERNAME',
                       os.environ.get('HOSTNAME',
                       os.popen('hostname').read().strip()))
    if os.name == 'nt':
        info['os_type'] = 'windows'
        try:
            info['is_admin'] = bool(ctypes.windll.shell32.IsUserAnAdmin())
        except Exception:
            info['is_admin'] = False
        info['username'] = os.environ.get('USERNAME', '')
        try:
            out = subprocess.check_output('whoami /groups /fo csv',
                                          shell=True, text=True, timeout=10,
                                          stderr=subprocess.DEVNULL)
            for line in out.strip().split('\n')[1:]:
                parts = line.strip('"').split('","')
                if parts:
                    info['groups'].append(parts[0])
        except Exception:
            pass
        try:
            out = subprocess.check_output('whoami /priv',
                                          shell=True, text=True, timeout=10,
                                          stderr=subprocess.DEVNULL)
            if 'SeDebugPrivilege' in out:
                info['integrity_level'] = 'high'
            elif 'SeChangeNotifyPrivilege' in out:
                info['integrity_level'] = 'medium'
        except Exception:
            pass
    else:
        info['os_type'] = 'linux' if sys.platform.startswith('linux') else 'macos'
        info['uid'] = os.getuid()
        info['is_admin'] = os.getuid() == 0
        info['username'] = os.environ.get('USER', os.environ.get('LOGNAME', ''))
        if not info['username']:
            try:
                info['username'] = subprocess.check_output(['whoami'],
                                                            text=True, timeout=5).strip()
            except Exception:
                pass
        try:
            out = subprocess.check_output(['id', '-Gn'],
                                           text=True, timeout=5).strip()
            info['groups'] = out.split()
        except Exception:
            try:
                out = subprocess.check_output(['groups'],
                                               text=True, timeout=5).strip()
                info['groups'] = out.split()
            except Exception:
                pass
        interesting = {'sudo', 'wheel', 'root', 'admin', 'docker', 'lxd', 'disk', 'adm'}
        info['interesting_groups'] = [g for g in info['groups'] if g in interesting]
    return info
